settings.customCSS:
html{scroll-behavior: smooth;}
.faq-tp-pad {  padding-top: 50px;}
.faq-tab-cont {
    display: flex;
    flex-wrap: wrap;
    justify-content: center;
    align-items: center;max-width: 550px;
}
 .faq-tab-cont a {   
 text-decoration: none;
    margin-top: 10px;
    padding: 4px 16px;
    border: 1px solid #58327a;
    border-radius: 5px;
    margin-left: 4px;
    margin-right: 4px;
    color: #58327a !important;
}

